<template>
  <div>
    <div class='contianer-fluid topBar' ref='topBar'>
      <div class='row'>

        <div class='col-10'>
          <div class='row'>
            <div class='col-1 label font-weight-bold'>Key</div>
            <div class='col-11'>
              <div class='row'>
                <div class='col fixed-height'><div class='edu swatch'></div>Academics</div>
                <div class='col fixed-height'><div class='ath swatch'></div>Athletics & Rec</div>
                <div class='col fixed-height'><div class='din swatch'></div>Dining</div>
                <div class='col fixed-height'><div class='com swatch'></div>Events & Admin</div>
                <div class='col fixed-height'><div class='res swatch'></div>Residence</div>
              </div>
            </div>
          </div>
        </div>
        <div class='col text-right'>
          <b-dropdown class='d-inline-block' toggle-class='mapFilterBtn' size='sm' right menu-class='dropdownArea' text='Filter' ref='mapFilter'>
            <b-dropdown-header>Building Type</b-dropdown-header>
            <b-dropdown-item-button disabled> <input type="checkbox" value='Residence' v-model="selected" checked> Residence </b-dropdown-item-button>
            <b-dropdown-item-button disabled> <input type="checkbox" value='Athletics' v-model="selected" checked> Athletics & Rec </b-dropdown-item-button>
            <b-dropdown-item-button disabled> <input type="checkbox" value='Dining' v-model="selected" checked> Dining </b-dropdown-item-button>
            <b-dropdown-item-button disabled> <input type="checkbox" value='Academics' v-model="selected" checked> Academics </b-dropdown-item-button>
            <b-dropdown-item-button disabled> <input type="checkbox" value='Admin' v-model="selected" checked> Events & Admin </b-dropdown-item-button>
          </b-dropdown>
        </div>
      </div>
    </div>
    <div class='mapContainer' ref='mapContainer'>
      <l-map style="height: 100%; width: 100%;" :zoom="zoom" :center="center" ref='map'>
        <l-tile-layer :url="url" :attribution="attribution"></l-tile-layer>
        <l-geo-json :key='rKey' :geojson='this.polygonData' :options='buildingOptions' ref="geoLayer"></l-geo-json>
      </l-map>
    </div>
    <transition name='side'>
      <sideView v-bind:key='openStory' ref='sideview' v-if='showSide'></sideView>
    </transition>
  </div>
</template>
<script>
import { LMap, LTileLayer, LMarker, LPolygon, LGeoJson } from 'vue2-leaflet'
import sideView from '@/components/map/sideView'
import L from 'leaflet'

export default {
  name: 'featured',
  components: {
    LMap,
    LTileLayer,
    LMarker,
    LPolygon,
    sideView,
    LGeoJson
  },
  data () {
    return {
      zoom: 15.5,
      center: L.latLng(44.565, -123.2785),
      url: 'https://api.mapbox.com/styles/v1/jack-woods/cjmi2qpp13u4o2spgb66d07ci/tiles/256/{z}/{x}/{y}?access_token=pk.eyJ1IjoiamFjay13b29kcyIsImEiOiJjamg2aWpjMnYwMjF0Mnd0ZmFkaWs0YzN0In0.qyiDXCvvSj3O4XvPsSiBkA',
      attribution: '&copy; <a href="http://osm.org/copyright">OpenStreetMap</a> contributors',
      map: null,
      polygonData: null,
      openStory: 0,
      showSide: false,
      ele: [],
      rKey: 0,
      selected: ['Residence', 'Athletics', 'Dining', 'Academics', 'Admin'],
      show: false,
      buildingOptions: {
        onEachFeature: function (feature, layer) {
          layer.on('click', function (e) { window.vue.$eventHub.$emit('clickedPolygon', [feature.properties.story_id]) })
          layer.on('mouseover', function (e) {
            e.target.setStyle({ fillColor: '#000', color: '#000' })
            e.target.bindTooltip(e.target.feature.properties.name).openTooltip()
          })
          layer.on('mouseout', (e) => { window.vue.$eventHub.$emit('resetPolygon', [e.target]) })
        },
        style: function (feature) {
          var color = '#000'
          switch (feature.properties.affiliation) {
            case 'Residence':
              color = '#D3832B'
              break
            case 'Academics':
              color = '#0D5257'
              break
            case 'Admin':
              color = '#7A6855'
              break
            case 'Athletics':
              color = '#FFB500'
              break
            case 'Dining':
              color = '#4A773C'
              break
            default:
              break
          }
          return {
            weight: 2,
            color: color,
            opacity: 1,
            fillColor: color,
            fillOpacity: 0.7
          }
        }
      }
    }
  },
  methods: {
    polyClick: function (value) {
      this.showSide = true
      this.openStory = value
    }
  },
  created () {
    this.$store.dispatch('mapdata').then(r => {
      this.polygonData = r
    })
    this.$eventHub.$on('clickedPolygon', (v) => (this.polyClick(v[0])))
    this.$eventHub.$on('resetPolygon', (v) => { this.$refs.geoLayer.mapObject.resetStyle(v[0]) })
  },
  mounted () {
    this.$nextTick(() => {
      this.map = this.$refs.map.mapObject
      this.$refs.mapContainer.style.height = (window.innerHeight - 80 - this.$refs.topBar.clientHeight).toString() + 'px'
      window.addEventListener('resize', () => {
        this.$refs.mapContainer.style.height = (window.innerHeight - 80 - this.$refs.topBar.clientHeight).toString() + 'px'
      })
    })
  },
  beforeDestroy () {
    this.$eventHub.$off('clickedPolygon')
    this.$eventHub.$off('resetPolygon')
  },
  watch: {
    selected: function (val) {
      this.rKey++
      //  L.geoJSON(this.polygonData).addTo(this.map);
      this.$nextTick(() => {
        for (var layerKey of Object.keys(this.map._layers)) {
          var layer = this.map._layers[layerKey]
          if (layer.feature) {
            if (!val.includes(layer.feature.properties.affiliation)) {
              this.map.removeLayer(layer)
            }
          }
        }
      })
    }
  }
}
</script>

<style >

@import "../../../node_modules/leaflet/dist/leaflet.css";
.dropdownArea {
  width: 350px;
}
.dropdownArea > a:active {
  background-color: rgba(0,0,0,0);
}
.dropdownArea > a:active > * {
  color: rgb(26,26,26) !important;
}
.dropdownArea > a > * {
  color: rgb(26,26,26);
}
.mapFilterBtn {
  background-color: #FFF !important;
  color: #000 !important;
  border: solid 1px #000 !important;
}
.mapFilterBtn:hover {
  background-color: rgba(0,0,0,0.15) !important;
  color: #000 !important;
  border: solid 1px #000 !important;
}
.mapFilterBtn:active {
  background-color: rgba(0,0,0,0.1) !important;
  color: #000 !important;
  border: solid 1px #000 !important;
}
</style>
<style scoped>
.dropdown-header {
  font-weight: bold;
  color: #000 !important;
  font-size: 16px;
}
.dropdown-item.disabled, .dropdown-item:disabled {
  color: #000 !important;
}
.fixed-height {
  white-space: nowrap;
}
.mapContainer {
  background-color: blue;
  height: 100vh;
  width: 100%;
}
.main {
  position: absolute;
  top: 4em;
  width:100%;
  height: calc(100% - 4em);
}
.topBar {
  box-shadow: 0px 1px 4px rgba(0,0,0,0.5);
  width:100%;
  position: relative;
  top: 0px;
  background-color: #FFF;
  padding: 1em;
  padding-left: 3em;
  padding-right: 3em;
}
.side-enter-active, .side-leave-active {
  transition: all 1s;
}
.side-enter {
  opacity: 0;
  transform: translateX(300px);
}
.side-enter-to {
  opacity: 1;
  transform: translateX(0px);
}
.side-leave {
  opacity: 1;
  transform: translateY(0px);
}
.side-leave-to /* .fade-leave-active below version 2.1.8 */ {
  opacity: 0;
  transform: translateY(500px);
}
.swatch {
  width: 20px;
  height: 10px;
  background-color: #000;
  display: inline-block;
  margin-right: 0.5em;
  border: solid 2px #000;
}
.res.swatch {
  background-color: #D3832BB3;
  border-color: #D3832B;
}
.ath.swatch {
  background-color: #FFB500B3;
  border-color: #FFB500;
}
.din.swatch {
  background-color: #4A773CB3;
  border-color: #4A773C;
}
.rch.swatch {
  background-color: #AA9D2EB3;
  border-color: #AA9D2E;
}
.edu.swatch {
  background-color: #0D5257B3;
  border-color: #0D5257;
}
.com.swatch {
  background-color: #7A6855B3;
  border-color: #7A6855;
}
.label {
  color: #000;
  font-size: 1em;
}
</style>



